React effect Hook，忽略第一次调用（例如在挂载时）。其签名与 `useEffect` Hook 完全相同。

## 示例

```tsx



const Demo = () => {
  const [count, setCount] = React.useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setCount((count) => count + 1);
    }, 1000);

    return () => {
      clearInterval(interval);
    };
  }, []);

  useUpdateEffect(() => {
    console.log("count", count); // will only show 1 and beyond

    return () => {
      // *OPTIONAL*
      // do something on unmount
    };
  }); // you can include deps array if necessary

  return <view>Count: {count}</view>;
};
```

## 类型定义

```ts


declare const useUpdateEffect: typeof useEffect;
```

List 滚动事件处理 Hook，支持过滤非用户触发的滚动事件。

## 基础示例

```tsx


export function List() {
  const { listScrollEventsAndAttrs } = useListScrollEvent({
    onScroll: (e) => {
      console.log("on scroll", e);
    },
    onScrollToUpper: (e) => {
      console.log("on scroll to upper", e);
    },
    onScrollToLower: (e) => {
      console.log("on scroll to lower", e);
    }
  });

  return (
    <list {...listScrollEventsAndAttrs} />
  );
}
```

## 使用 Options 选项

```tsx


export function List() {
  const { listScrollEventsAndAttrs } = useListScrollEvent({
    onScroll: (e) => {
      console.log("on scroll", e);
    },
    onScrollToUpper: (e) => {
      console.log("on scroll to upper", e);
    },
    onScrollToLower: (e) => {
      console.log("on scroll to lower", e);
    }
  }, {
    filterScrollToLowerEventWithEventSource: true,
    filterScrollToUpperEventWithEventSource: true,
    scrollEventThrottle: 50,
    upperThresholdItemCount: 2,
    lowerThresholdItemCount: 2
  });

  return (
    <list {...listScrollEventsAndAttrs} />
  );
}
```

## 类型定义

```ts
export type ListScrollEventAttrsBag = {
  "scroll-event-throttle"?: number;
  "upper-threshold-item-count"?: number;
  "lower-threshold-item-count"?: number;
};

export interface IUseListScrollEventHandlers {
  onScroll?: (e: ListScrollEvent) => void;
  onScrollToUpper?: (e: ListScrollToUpperEvent) => void;
  onScrollToLower?: (e: ListScrollToLowerEvent) => void;
}

export interface IUseListScrollEventOptions {
  filterScrollToLowerEventWithEventSource?: boolean;
  filterScrollToUpperEventWithEventSource?: boolean;
  scrollEventThrottle?: number;
  upperThresholdItemCount?: number;
  lowerThresholdItemCount?: number;
}

export interface IUseListScrollEventReturn {
  listScrollEventsAndAttrs: {
    bindscroll?: (e: ListScrollEvent) => void;
    bindscrolltoupper?: (e: ListScrollToUpperEvent) => void;
    bindscrolltolower?: (e: ListScrollToLowerEvent) => void;
  } & ListScrollEventAttrsBag;
}
```

主线程版本的 React 的 [useImperativeHandle]()，用于在主线程向父组件暴露命令式方法。

## 示例

```tsx




interface InternalCompMTRef {
  start: () => void;
}

function InternalComp({
  "main-thread:ref": MTRef,
}: {
  "main-thread:ref"?: MainThreadRef<InternalCompMTRef | null>;
}) {
  function start() {
    "main thread";
    console.log("MT Start");
  }

  useMainThreadImperativeHandle(
    MTRef,
    () => {
      "main thread";
      return {
        start: start,
      };
    },
    []
  );

  return (
    <view>
      <text>Internal Comp</text>
    </view>
  );
}

function App() {
  const internalMTRef = useMainThreadRef<InternalCompMTRef>(null);

  return (
    <view>
      <InternalComp main-thread:ref={internalMTRef} />
      <view
        main-thread:bindtap={() => {
          "main thread";
          internalMTRef.current?.start();
        }}
      >
        <text>Click to Trigger</text>
      </view>
    </view>
  );
}
```

## 类型定义

```ts


function useMainThreadImperativeHandle<T, R extends T>(
  ref: MainThreadRef<T> | undefined,
  createHandle: () => R,
  deps: readonly unknown[]
): void;
```

用于将 [`TouchEvent`]() 与 [`MouseEvent`]() 统一为 `PointerEvent` 的 hook，便于跨平台处理指针事件。

## 示例

```tsx


function App() {
  const pointerHandlers = usePointerEvent({
    onPointerDown: (event: CustomPointerEvent) => {
      console.log("Pointer down", event);
    },
    onPointerDownMT: (event: CustomPointerEventMT) => {
      'main thread'
      console.log("Pointer down on main thread", event);
    },
  });

  return <view {...pointerHandlers}></view>
}

```

## 类型定义

```tsx
type PointerAction = 'pointerdown' | 'pointermove' | 'pointerup';

interface CustomPointerEvent {
    type: PointerAction;
    pointerType: 'mouse' | 'touch';
    x: number;
    y: number;
    pointerId: number;
    isPrimary: boolean;
    pageX?: number;
    pageY?: number;
    clientX?: number;
    clientY?: number;
    button?: number;
    buttons?: number;
    identifier?: number;
    originalEvent: unknown;
}

interface CustomPointerEventMT extends CustomPointerEvent {
    target: MainThread.Element;
    currentTarget: MainThread.Element;
    originalEvent: MainThread.MouseEvent | MainThread.TouchEvent;
}

function usePointerEvent({ onPointerDown, onPointerUp, onPointerMove, onPointerUpMT, onPointerMoveMT, onPointerDownMT, }: {
    onPointerDown?: (event: CustomPointerEvent) => void;
    onPointerUp?: (event: CustomPointerEvent) => void;
    onPointerMove?: (event: CustomPointerEvent) => void;
    onPointerUpMT?: (event: CustomPointerEventMT) => void;
    onPointerMoveMT?: (event: CustomPointerEventMT) => void;
    onPointerDownMT?: (event: CustomPointerEventMT) => void;
}): {
    'bindmousedown'?: (e: MouseEvent) => void;
    'bindtouchstart'?: (e: TouchEvent) => void;
    'bindmousemove'?: (e: MouseEvent) => void;
    'bindtouchmove'?: (e: TouchEvent) => void;
    'bindmouseup'?: (e: MouseEvent) => void;
    'bindtouchend'?: (e: TouchEvent) => void;
    'main-thread:bindmousedown'?: (e: MainThread.MouseEvent) => void;
    'main-thread:bindtouchstart'?: (e: MainThread.TouchEvent) => void;
    'main-thread:bindmousemove'?: (e: MainThread.MouseEvent) => void;
    'main-thread:bindtouchmove'?: (e: MainThread.TouchEvent) => void;
    'main-thread:bindmouseup'?: (e: MainThread.MouseEvent) => void;
    'main-thread:bindtouchend'?: (e: MainThread.TouchEvent) => void;
};

```

用于在给定方向中超过指定阈值时锁定 tap 事件的 hook。

## 示例

```tsx


function Demo() {
  const { tapLockRef, handleTouchStart, handleTouchMove, handleTouchEnd } =
    useTapLock();

  const handleTap = () => {
    if (tapLockRef.current) {
      console.log("Tap allowed");
    } else {
      console.log("Tap locked due to movement");
    }
  };

  return (
    <view
      main-thread:bindtouchstart={handleTouchStart}
      main-thread:bindtouchmove={handleTouchMove}
      main-thread:bindtouchend={handleTouchEnd}
      bindtap={handleTap}
    >
      Tap me
    </view>
  );
}
```

## 类型定义

```ts


type TapLockDirection = 'x' | 'y' | 'both';

interface UseTapLockOptions {
  /**
   * Movement threshold in pixels
   * @default 8
   */
  tapThreshold?: number;

  /**
   * Direction to monitor
   * @default 'x'
   */
  direction?: TapLockDirection;
}

function useTapLock(options?: UseTapLockOptions): {
  tapLockRef: import("@lynx-js/react").MainThreadRef<boolean>;
  handleTouchStart: (event: MainThread.TouchEvent) => void;
  handleTouchMove: (event: MainThread.TouchEvent) => boolean;
  handleTouchEnd: (event: MainThread.TouchEvent) => boolean;
};
```

用于从 [`MouseEvent`]() 合成 [`TouchEvent`]() 的 hook，使现有基于触摸的事件处理逻辑可以无缝兼容鼠标输入，便于从仅触摸代码迁移。

## 示例

```tsx


function App() {
  const touchHandlers = useTouchEmulation({
    onTouchStart: (event: TouchEvent) => {
      console.log("Touch start", event);
    },
    onTouchStartMT: (event: MainThread.TouchEvent) => {
      'main thread'
      console.log("Touch start on main thread", event);
    },
  });

  return <view {...touchHandlers}></view>
}
```

## 类型定义

```tsx
type TouchAction = 'touchstart' | 'touchmove' | 'touchend';

function useTouchEmulation({
  onTouchStart,
  onTouchMove,
  onTouchEnd,
  onTouchStartMT,
  onTouchMoveMT,
  onTouchEndMT,
}: {
  onTouchStart?: (event: TouchEvent) => void;
  onTouchMove?: (event: TouchEvent) => void;
  onTouchEnd?: (event: TouchEvent) => void;
  onTouchStartMT?: (event: MainThread.TouchEvent) => void;
  onTouchMoveMT?: (event: MainThread.TouchEvent) => void;
  onTouchEndMT?: (event: MainThread.TouchEvent) => void;
}): {
  'bindtouchstart'?: (e: TouchEvent) => void;
  'bindmousedown'?: (e: MouseEvent) => void;
  'bindtouchmove'?: (e: TouchEvent) => void;
  'bindmousemove'?: (e: MouseEvent) => void;
  'bindtouchend'?: (e: TouchEvent) => void;
  'bindmouseup'?: (e: MouseEvent) => void;
  'main-thread:bindtouchstart'?: (e: MainThread.TouchEvent) => void;
  'main-thread:bindmousedown'?: (e: MainThread.MouseEvent) => void;
  'main-thread:bindtouchmove'?: (e: MainThread.TouchEvent) => void;
  'main-thread:bindmousemove'?: (e: MainThread.MouseEvent) => void;
  'main-thread:bindtouchend'?: (e: MainThread.TouchEvent) => void;
  'main-thread:bindmouseup'?: (e: MainThread.MouseEvent) => void;
};

// 别名：useTouchEvent 提供相同的 API
```

用于跟踪 tap 速度和方向的 hook。

## 示例

```tsx


const Demo = () => {
  const { getVelocity, handleTouchStartMT, handleTouchMoveMT } = useVelocity({
    smoothingFactor: 0.2,
    maxTimeDelta: 100,
    RTL: false,
  });

  return (
    <view
      main-thread:bindtouchstart={handleTouchStartMT}
      main-thread:bindtouchmovee={handleTouchMoveMT}
      main-thread:bindtouchend={() => {
        "main thread";
        const { velocity, direction } = getVelocity();
        console.log(`Velocity: ${velocity}px/s, Direction: ${direction}`);
      }}
    >
      <text>Swipe me!</text>
    </view>
  );
};
```

## 类型定义

```ts

export type Direction = 'forward' | 'backward' | 'none';
export interface UseVelocityOptions {
    RTL?: boolean;
    smoothingFactor?: number;
    maxTimeDelta?: number;
}
export interface VelocityResult {
    velocity: number;
    direction: Direction;
}
export interface UseVelocityReturn {
    getVelocity: () => VelocityResult;
    handleTouchStartMT: (event: MainThread.TouchEvent) => void;
    handleTouchMoveMT: (event: MainThread.TouchEvent) => void;
}
export default function useVelocity(options?: UseVelocityOptions): UseVelocityReturn;
```

